/* https://codeforces.com/contest/653/submission/19859515 (rainboy) */
#include <stdio.h>

#define Q	36

int main() {
	static char ab[Q][4], cc[Q];
	static int dp[6][6];
	int n, q, i, j, k;

	scanf("%d%d\n", &n, &q);
	for (i = 0; i < q; i++)
		scanf("%s %c", ab[i], &cc[i]);
	for (i = 0; i < 6; i++)
		dp[0][i] = 1;
	for (i = 1; i < n; i++)
		for (j = 0; j < 6; j++)
			for (k = 0; k < q; k++)
				if (j + 'a' == cc[k])
					dp[i][j] += dp[i - 1][ab[k][0] - 'a'];
	printf("%d\n", dp[n - 1][0]);
	return 0;
}

