fn run() {
    input! {
        n: usize,
        q: usize,
        op: [(bytes, bytes); q],
    }
    let mut p = vec![];
    for (a, b) in op {
        let a = (a[1] - b'a') as usize * 6 + (a[0] - b'a') as usize;
        let b = (b[0] - b'a') as usize;
        p.push((a, b));
    }
    let mut ok = vec![false; 6];
    ok[0] = true;
    for _ in 2..=n {
        let mut next = vec![false; ok.len() * 6];
        for (i, _) in ok.iter().enumerate().filter(|p| *p.1) {
            for &(a, b) in p.iter() {
                if i % 6 == b {
                    next[(i / 6) * 36 + a] = true;
                }
            }
        }
        ok = next;
    }
    let ans = ok.into_iter().filter(|p| *p).count();
    println!("{}", ans);
}

fn main() {
    run();
}
